import{_ as o,H as a,f as t,i as n}from"./chunks/framework.DbTCwA-u.js";const g=JSON.parse('{"title":"Troubleshooting","description":"Common issues and solutions when using EligiusNametag.","frontmatter":{"title":"Troubleshooting","description":"Common issues and solutions when using EligiusNametag."},"headers":[],"relativePath":"troubleshooting.md","filePath":"troubleshooting.md"}'),s={name:"troubleshooting.md"};function r(i,e,l,h,d,u){return a(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h1><p>Having issues with EligiusNametag? Check these common solutions:</p><h3 id="_1-the-nametag-doesn-t-appear-above-the-player" tabindex="-1">1. The Nametag doesn&#39;t appear above the player <a class="header-anchor" href="#_1-the-nametag-doesn-t-appear-above-the-player" aria-label="Permalink to &quot;1. The Nametag doesn&#39;t appear above the player&quot;">​</a></h3><ul><li><strong>Do you have ProtocolLib installed?</strong> Our plugin strictly relies on packet injection so nametags float smoothly without causing lag.</li><li><strong>Do you have PlaceholderAPI installed?</strong> If you use variables like <code>%vault_rank%</code> and don&#39;t have PAPI, the text might fail to render.</li></ul><h3 id="_2-database-connection-closed-error" tabindex="-1">2. &quot;Database Connection Closed&quot; Error <a class="header-anchor" href="#_2-database-connection-closed-error" aria-label="Permalink to &quot;2. &quot;Database Connection Closed&quot; Error&quot;">​</a></h3><ul><li>This has been <strong>fixed in recent versions</strong>. Ensure you are running the latest version <code>v1.x.x</code> or higher. If you use <strong>MySQL</strong>, verify that the IP and credentials in <code>config.yml</code> are correct. Otherwise, use local <code>SQLITE</code>.</li></ul><h3 id="_3-viaversion-warnings-in-console" tabindex="-1">3. ViaVersion Warnings in Console <a class="header-anchor" href="#_3-viaversion-warnings-in-console" aria-label="Permalink to &quot;3. ViaVersion Warnings in Console&quot;">​</a></h3><p>If you use ViaVersion to allow players on 1.20 to join your 1.21+ server, you might see messages about <em>Metadata</em> and <em>Protocol Versions</em>.</p><ul><li><strong>Cause:</strong> The old client (e.g., 1.20.2) lacks the native code to properly process large <code>TEXT_DISPLAY</code> entities.</li><li><strong>Solution:</strong> We highly recommend requiring 1.21+ versions for perfect hologram visualization, or simply ignore the warning if the player experiences no visual crashes.</li></ul><h3 id="_4-enametag-lang-doesn-t-update-the-help-message" tabindex="-1">4. /enametag lang doesn&#39;t update the help message <a class="header-anchor" href="#_4-enametag-lang-doesn-t-update-the-help-message" aria-label="Permalink to &quot;4. /enametag lang doesn&#39;t update the help message&quot;">​</a></h3><p>When using <code>/enametag lang en</code>, the plugin reads from <code>lang/en.yml</code>. If you notice a translation is empty or a command acts weird, you can delete the <code>lang/</code> folder in your plugins directory so EligiusNametag can regenerate it cleanly with the latest standards.</p>',11)])])}const m=o(s,[["render",r]]);export{g as __pageData,m as default};
